#include "ca6k_02872_custom_tiling.h"
#include "register/op_def_registry.h"

namespace optiling {

static constexpr uint32_t UB_BUDGET_BYTES = 192 * 1024;  // per core
static constexpr uint32_t ALIGN_ELEMS = 1024;             // align to 1024 for DMA
static constexpr uint32_t HARD_CAP_ELEMS = 32768;

static inline uint32_t AlignDown(uint32_t x, uint32_t a) {
    return (x / a) * a;
}

static inline uint32_t CeilDiv(uint32_t a, uint32_t b) {
    return (a + b - 1u) / b;
}

static ge::graphStatus TilingFunc(gert::TilingContext *context) {
    Ca6k02872CustomTilingData tiling;
    uint32_t totalX = static_cast<uint32_t>(context->GetInputShape(0)->GetOriginShape().GetShapeSize());
    uint32_t divisorLen = static_cast<uint32_t>(context->GetInputShape(1)->GetOriginShape().GetShapeSize());

    // UB model: 2 tiles in (x), 2 tiles out (y), 1 temp (for reciprocal) + 1 copy of divisor
    // divisorLen is small (<=512), we reserve it separately.
    // For each tile we need: 2*tilen floats (x tile + y tile) + 1*tilen temp = 3*tilen floats
    // plus full divisor (divisorLen floats).
    // Total floats in UB = 3 * tileLen + divisorLen. Convert to bytes: *4.
    // UB budget: 192KB = 49152 floats. So we can compute max tile.
    uint32_t maxTileFloat = (49152 - divisorLen) / 3;
    if (maxTileFloat < 256) maxTileFloat = 256;  // minimum tile
    uint32_t tileLen = AlignDown(maxTileFloat, ALIGN_ELEMS);
    if (tileLen == 0) tileLen = ALIGN_ELEMS;
    if (tileLen > HARD_CAP_ELEMS) tileLen = HARD_CAP_ELEMS;

    // Ensure tileLen is a multiple of divisorLen for simpler broadcast
    if (divisorLen > 0) {
        uint32_t mult = CeilDiv(tileLen, divisorLen) * divisorLen;
        if (mult > HARD_CAP_ELEMS) mult = AlignDown(HARD_CAP_ELEMS, divisorLen);
        if (mult < divisorLen) mult = divisorLen;
        tileLen = mult;
    }

    if (totalX < tileLen) {
        uint32_t aligned = AlignDown(totalX, divisorLen);
        tileLen = (aligned > 0) ? aligned : totalX;
    }

    const uint32_t numTiles = (tileLen == 0) ? 1u : CeilDiv(totalX, tileLen);
    uint32_t blockDim = numTiles;
    if (blockDim < 8u) blockDim = 8u;
    if (blockDim > 24u) blockDim = 24u;

    context->SetBlockDim(blockDim);

    // Use underscored field names (macro generates _ suffix)
    tiling.totalLength_ = totalX;
    tiling.tileLength_ = tileLen;
    tiling.blockDim_ = blockDim;
    tiling.divisorLength_ = divisorLen;

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *currentWorkspace = context->GetWorkspaceSizes(1);
    currentWorkspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}

} // namespace optiling

